input.command:
CSV=/tmp/rbm_stuck_projects.csv
echo "days_until_purge  freed_that_day  cumulative_freed"
tail -n +2 "$CSV" | awk -F, '$4 ~ /^[0-9]+$/ {u=30-$4; if(u<0)u=0; cnt[u]++} END {
  cum=0;
  for(d=0; d<=30; d++){ if(cnt[d]>0){ cum+=cnt[d]; printf "%3d days          %3d             %3d\n", d, cnt[d], cum } }
}'
echo
echo "Earliest purge (next batch):"
tail -n +2 "$CSV" | awk -F, '$4 ~ /^[0-9]+$/ {print 30-$4}' | sort -n | head -1 | awk '{print "  "$1" days from now"}'

